# Background: the isaac-sim MCP server's capture_image tool failed repeatedly on
# this host with "'NoneType' has no __array_interface__", regardless of which
# camera was targeted, whether a render product was pre-attached, or whether the
# timeline was playing. The render product's RGB annotator kept returning None.
#
# This helper bypasses the broken tool path by using the isaacsim.sensors.camera
# Camera sensor directly, which has its own image-grab pipeline. It runs as a
# one-shot execute_script payload inside Kit's event loop.
#
# Reconstructed from the chat narrative; this is not a verbatim transcript of
# the inline script because the original was authored via execute_script calls
# rather than as a saved file.
"""
Capture a frame from /World/SceneCamera and save it to /tmp/scene_capture.png
on the Isaac Sim host.
"""

import asyncio
import numpy as np
import omni.kit.app
import omni.usd
from isaacsim.sensors.camera import Camera

CAMERA_PRIM = "/World/SceneCamera"
OUT_PATH    = "/tmp/scene_capture.png"
RESOLUTION  = (1920, 1080)   # downscaled in a later step to fit a single
                             # base64 chunk for transport back to the MCP client


async def _pump_app(n: int):
    """Yield to Kit's event loop n times so the renderer can produce a frame."""
    app = omni.kit.app.get_app()
    for _ in range(n):
        await app.next_update_async()


async def _capture():
    cam = Camera(prim_path=CAMERA_PRIM, resolution=RESOLUTION)
    cam.initialize()

    # The renderer needs several updates to actually produce pixels after a
    # Camera is (re)initialized. 30 frames is generous; less can leave the
    # annotator returning a (0,) shaped buffer.
    await _pump_app(30)

    rgba = cam.get_rgba()
    if rgba is None or rgba.size == 0:
        raise RuntimeError(f"camera annotator returned no pixels: shape="
                           f"{None if rgba is None else rgba.shape}")

    # Drop alpha and save
    from PIL import Image
    rgb = rgba[..., :3].astype(np.uint8)
    Image.fromarray(rgb).save(OUT_PATH)
    print(f"saved {rgb.shape} frame to {OUT_PATH}")
    return rgb.shape


# Kick the capture off; execute_script runs inside Kit so we have an event loop.
asyncio.ensure_future(_capture())
